  body += "--\(boundary)\r
"
  body += "Content-Disposition:form-data; name="\(paramName)""
  if let filename = param["fileName"] {
    let contentType = param["content-type"]!
    let fileContent = String(contentsOfFile: filename, encoding: String.Encoding.utf8)
